import{_ as e,a as t,b as n,c as i}from"./chunks/查询额度成功.BYPQR2qF.js";import{_ as d,o as r,c as l,a2 as s}from"./chunks/framework.DnrXFDHb.js";const y=JSON.parse('{"title":"Tambah WebDAV Channel","description":"","frontmatter":{},"headers":[],"relativePath":"ms-MY/upload/webdav.md","filePath":"ms-MY/upload/webdav.md","lastUpdated":1781962217000}'),o={name:"ms-MY/upload/webdav.md"};function u(p,a,c,h,m,k){return r(),l("div",null,[...a[0]||(a[0]=[s('<h1 id="tambah-webdav-channel" tabindex="-1">Tambah WebDAV Channel <a class="header-anchor" href="#tambah-webdav-channel" aria-label="Permalink to &quot;Tambah WebDAV Channel&quot;">​</a></h1><h2 id="paling-sesuai-untuk" tabindex="-1">Paling Sesuai Untuk <a class="header-anchor" href="#paling-sesuai-untuk" aria-label="Permalink to &quot;Paling Sesuai Untuk&quot;">​</a></h2><p>Gunakan WebDAV channel apabila:</p><ul><li>Anda mempunyai NAS, cloud drive atau object storage service yang menyediakan WebDAV endpoint.</li><li>Anda mahu uploaded images disimpan dalam WebDAV directory milik anda.</li><li>Anda mahu credentials disimpan dalam D1 <code>upload_channels</code> table, bukan didedahkan lama di frontend.</li></ul><h2 id="perkara-yang-perlu-disediakan" tabindex="-1">Perkara Yang Perlu Disediakan <a class="header-anchor" href="#perkara-yang-perlu-disediakan" aria-label="Permalink to &quot;Perkara Yang Perlu Disediakan&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Requirement</th><th>Purpose</th></tr></thead><tbody><tr><td>WebDAV Endpoint</td><td>Server-side WebDAV URL, contohnya <code>https://nas.example.com/dav</code>.</td></tr><tr><td>Username</td><td>Digunakan untuk sign in ke WebDAV service.</td></tr><tr><td>Password</td><td>Digunakan untuk sign in ke WebDAV service.</td></tr><tr><td>Authentication mode</td><td>Default ialah <code>Basic</code>. Gunakan <code>Digest</code> atau auto negotiation hanya jika server memerlukannya.</td></tr><tr><td>Storage directory</td><td>Directory untuk menyimpan files. Default ialah <code>imgbed</code>.</td></tr></tbody></table><h2 id="di-mana-untuk-menambahnya" tabindex="-1">Di Mana Untuk Menambahnya <a class="header-anchor" href="#di-mana-untuk-menambahnya" aria-label="Permalink to &quot;Di Mana Untuk Menambahnya&quot;">​</a></h2><ol><li>Buka System Settings.</li><li>Pergi ke Upload Settings.</li><li>Klik Add Channel di penjuru kanan atas.</li><li>Pilih <code>WebDAV</code>.</li></ol><h2 id="field-reference" tabindex="-1">Field Reference <a class="header-anchor" href="#field-reference" aria-label="Permalink to &quot;Field Reference&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Field</th><th>Fungsi</th><th>Required</th></tr></thead><tbody><tr><td>Channel name</td><td>Nama mudah dikenali untuk WebDAV channel, contohnya <code>koofr</code> atau <code>nas</code>.</td><td>Yes</td></tr><tr><td>Endpoint</td><td>Full WebDAV endpoint termasuk <code>https://</code>.</td><td>Yes</td></tr><tr><td>Username</td><td>WebDAV login username.</td><td>Yes</td></tr><tr><td>Password</td><td>WebDAV login password.</td><td>Yes</td></tr><tr><td>Authentication mode</td><td>Biasanya <code>Basic</code>; gunakan <code>Digest</code> jika server memerlukan digest authentication.</td><td>Yes</td></tr><tr><td>Storage directory</td><td>Directory tempat files disimpan. Default ialah <code>imgbed</code>.</td><td>No</td></tr></tbody></table><h2 id="example-fie-nl-tab-digital" tabindex="-1">Example: fie.nl.tab.digital <a class="header-anchor" href="#example-fie-nl-tab-digital" aria-label="Permalink to &quot;Example: fie.nl.tab.digital&quot;">​</a></h2><h3 id="_1-cipta-app-password" tabindex="-1">1. Cipta App Password <a class="header-anchor" href="#_1-cipta-app-password" aria-label="Permalink to &quot;1. Cipta App Password&quot;">​</a></h3><p>Buka account security settings, cari application passwords dan cipta app password baharu.</p><p><img src="'+e+'" alt="Create an app password" loading="lazy"></p><p>Selepas dicipta, copy dan simpan app password baharu. Biasanya ia hanya dipaparkan sekali.</p><p><img src="'+t+'" alt="Save the new app password" loading="lazy"></p><h3 id="_2-isi-webdav-configuration-dalam-imgbed" tabindex="-1">2. Isi WebDAV Configuration Dalam ImgBed <a class="header-anchor" href="#_2-isi-webdav-configuration-dalam-imgbed" aria-label="Permalink to &quot;2. Isi WebDAV Configuration Dalam ImgBed&quot;">​</a></h3><p>Kembali ke ImgBed dan tambah WebDAV channel:</p><table tabindex="0"><thead><tr><th>UI Field</th><th>Value</th></tr></thead><tbody><tr><td>Endpoint</td><td>WebDAV URL yang diberi oleh <code>https://fie.nl.tab.digital/</code>.</td></tr><tr><td>Username</td><td>WebDAV username anda.</td></tr><tr><td>Password</td><td>App password yang baru dicipta.</td></tr><tr><td>Authentication mode</td><td>Mulakan dengan <code>Basic</code> dalam kebanyakan keadaan.</td></tr><tr><td>Storage directory</td><td>Default ialah <code>imgbed</code>; boleh juga gunakan custom directory.</td></tr></tbody></table><p><img src="'+n+'" alt="Fill in the configuration" loading="lazy"></p><h2 id="kelakuan-upload-file-besar" tabindex="-1">Kelakuan Upload File Besar <a class="header-anchor" href="#kelakuan-upload-file-besar" aria-label="Permalink to &quot;Kelakuan Upload File Besar&quot;">​</a></h2><p>WebDAV channel kini menggunakan real session-based chunked upload.</p><p>Small files di-upload sebagai satu complete file. Files lebih besar daripada 64 MiB akan dipecahkan secara automatik kepada chunks sekitar 10 MiB dan di-upload ke remote chunk directory.</p><p>WebDAV service tidak perlu menyokong <code>partial update</code> atau offset-based writes. ImgBed tidak merge chunks menjadi satu large file pada remote server. Sebaliknya, ia menyimpan chunk manifest dan membaca chunks mengikut turutan apabila file diminta.</p><p>Dalam praktik:</p><table tabindex="0"><thead><tr><th>File Size</th><th>Upload Method</th><th>Remote Storage Layout</th></tr></thead><tbody><tr><td>64 MiB atau kurang</td><td>Normal upload</td><td>Satu complete file</td></tr><tr><td>Lebih besar daripada 64 MiB</td><td>Real session chunked upload</td><td>Chunk directory yang mengandungi beberapa chunk files</td></tr></tbody></table><p>Chunk directory hanya mempengaruhi remote storage layout. Ia tidak mengubah file URL dalam ImgBed. Users masih mengakses file melalui link asal <code>/file/...</code>.</p><h2 id="langkah-setup" tabindex="-1">Langkah Setup <a class="header-anchor" href="#langkah-setup" aria-label="Permalink to &quot;Langkah Setup&quot;">​</a></h2><ol><li>Buka Upload Settings.</li><li>Klik Add Channel.</li><li>Pilih <code>WebDAV</code>.</li><li>Masukkan channel name yang mudah dikenali, contohnya <code>koofr</code>.</li><li>Masukkan WebDAV endpoint, contohnya <code>https://app.koofr.net/dav/Koofr</code>.</li><li>Masukkan username dan password.</li><li>Kekalkan authentication mode sebagai <code>Basic</code> secara default.</li><li>Kekalkan storage directory sebagai <code>imgbed</code>, atau tukar kepada directory anda sendiri.</li><li>Klik Save.</li><li>Selepas save, semak channel card, query capacity jika tersedia, dan upload test file.</li></ol><h2 id="cara-menyemak" tabindex="-1">Cara Menyemak <a class="header-anchor" href="#cara-menyemak" aria-label="Permalink to &quot;Cara Menyemak&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Check</th><th>Cara Menyemak</th></tr></thead><tbody><tr><td>Channel card muncul</td><td>Selepas save, halaman Upload Settings patut memaparkan WebDAV channel card.</td></tr><tr><td>Channel enabled</td><td>Switch di penjuru kanan atas card patut kekal on.</td></tr><tr><td>Credentials disimpan</td><td>Detail view patut memaparkan Endpoint, username, authentication mode dan storage directory.</td></tr><tr><td>Small file upload berfungsi</td><td>Upload test image dan pastikan file muncul dalam WebDAV directory.</td></tr><tr><td>Large file rule berfungsi</td><td>Files lebih besar daripada 64 MiB menggunakan chunked upload dan mencipta remote chunk directory.</td></tr><tr><td>Capacity query berfungsi</td><td>Jika server menyokong capacity information, query akan menunjukkan used dan total capacity.</td></tr></tbody></table><p><img src="'+i+`" alt="Quota query succeeded" loading="lazy"></p><h2 id="faq" tabindex="-1">FAQ <a class="header-anchor" href="#faq" aria-label="Permalink to &quot;FAQ&quot;">​</a></h2><h3 id="mengapa-large-webdav-files-mencipta-chunk-directory" tabindex="-1">Mengapa large WebDAV files mencipta chunk directory? <a class="header-anchor" href="#mengapa-large-webdav-files-mencipta-chunk-directory" aria-label="Permalink to &quot;Mengapa large WebDAV files mencipta chunk directory?&quot;">​</a></h3><p>Ini ialah storage method semasa untuk large files.</p><p>Files lebih besar daripada 64 MiB tidak digabungkan menjadi satu remote file besar. Ia disimpan sebagai chunk directory. ImgBed merekod chunk manifest dan mengembalikan content lengkap dengan membaca chunks mengikut turutan.</p><h3 id="jika-large-file-upload-gagal-apa-yang-perlu-disemak-dahulu" tabindex="-1">Jika large file upload gagal, apa yang perlu disemak dahulu? <a class="header-anchor" href="#jika-large-file-upload-gagal-apa-yang-perlu-disemak-dahulu" aria-label="Permalink to &quot;Jika large file upload gagal, apa yang perlu disemak dahulu?&quot;">​</a></h3><p>Semak Endpoint, username, password dan storage directory dahulu. Kemudian pastikan WebDAV service membenarkan directory creation, file writing dan file reading.</p><p>Jika capacity query gagal tetapi small file upload berfungsi, server mungkin tidak menyokong atau mengehadkan capacity reporting. Itu tidak semestinya bermaksud upload tidak tersedia.</p><h3 id="authentication-mode-mana-patut-digunakan" tabindex="-1">Authentication mode mana patut digunakan? <a class="header-anchor" href="#authentication-mode-mana-patut-digunakan" aria-label="Permalink to &quot;Authentication mode mana patut digunakan?&quot;">​</a></h3><p>Mulakan dengan <code>Basic</code>.</p><p>Jika server jelas memerlukan digest authentication, gunakan <code>Digest</code>.</p><p>Jika tidak pasti, gunakan automatic negotiation.</p><h2 id="quick-checklist" tabindex="-1">Quick Checklist <a class="header-anchor" href="#quick-checklist" aria-label="Permalink to &quot;Quick Checklist&quot;">​</a></h2><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Sediakan WebDAV endpoint, username dan password</span></span>
<span class="line"><span>-&gt; Buka Upload Settings</span></span>
<span class="line"><span>-&gt; Add Channel</span></span>
<span class="line"><span>-&gt; Pilih WebDAV</span></span>
<span class="line"><span>-&gt; Masukkan Endpoint / username / password</span></span>
<span class="line"><span>-&gt; Kekalkan authentication mode sebagai Basic secara default</span></span>
<span class="line"><span>-&gt; Kekalkan storage directory sebagai imgbed secara default</span></span>
<span class="line"><span>-&gt; Save</span></span>
<span class="line"><span>-&gt; Query capacity</span></span>
<span class="line"><span>-&gt; Upload test file</span></span></code></pre></div>`,45)])])}const f=d(o,[["render",u]]);export{y as __pageData,f as default};
